// frontend/src/components/Layout.tsx
import React from 'react';
import Navbar from './Navbar';

interface LayoutProps {
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  return (
    // Arka planı daha modern, hafif bir gri/mavi tonuna (slate-50) çektik
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Navbar bileşeni üstte sabit kalabilir veya scroll olabilir */}
      <Navbar />

      {/* Ana İçerik Alanı */}
      <main className="flex-grow w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        {/* Sayfa geçişlerinde içeriğin havadan geliyormuş gibi durması için küçük bir animasyon */}
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          {children}
        </div>
      </main>

      {/* Footer Bölümü */}
      <footer className="w-full py-8 mt-auto border-t border-slate-200 bg-white">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-slate-400 text-xs font-medium tracking-widest uppercase italic">
            © 2026 Kitabevi Yazılım Mühendisliği Ödevi — <span className="text-blue-500 font-bold">Golden State Demo</span>
          </p>
          <div className="mt-2 flex justify-center gap-4 text-[10px] text-slate-300 uppercase tracking-tighter">
            <span>Kamyonet Lojistik</span>
            <span>•</span>
            <span>Full-Stack v2.0</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default Layout;
